const results = scenario.steps.map<{ premium: number } | { payout: number }>((step, index) => {
  if (step.op === "quote") {
    const previousQuotes = scenario.steps
      .slice(0, index)
      .filter((s) => s.op === "quote").length;
    return {
      premium: quote({
        items: step.items,
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        previousQuotes,
      }),
    };
  }
  const policyStep = scenario.steps[step.policy] as QuoteStep;
  return { payout: claim(step.incident, { items: policyStep.items }) };
});
return { results };
